# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
import pandas as pd

app = Flask(__name__)

# Dictionary to store image labels from annotators
label_store = {}

@app.route('/submit_label', methods=['POST'])
def submit_label():
    data = request.json
    image_id = data['image_id']
    label = data['label']

    if image_id not in label_store:
        label_store[image_id] = []

    label_store[image_id].append(label)

    return jsonify({"message": "Label submitted successfully"})

@app.route('/aggregate_labels', methods=['GET'])
def aggregate_labels():
    aggregated_data = {}
    
    for image_id, labels in label_store.items():
        majority_vote = max(set(labels), key=labels.count)
        aggregated_data[image_id] = majority_vote

    return jsonify(aggregated_data)

if __name__ == '__main__':
    app.run(debug=True)